+        assert!(et.matches_pattern("user_event.*"));
+        assert!(et.matches_pattern("user_event.account_created"));
+    }
+
+    #[test]
+    fn event_type_with_numbers_in_parts() {
+        let et = EventType::new("v2.message.new");
+        assert!(et.matches_pattern("v2.*"));
