+        match &c.parsed {
+            ConditionExpr::LogicalAnd(l, r) => {
+                assert!(matches!(l.as_ref(), ConditionExpr::Not(_)));
+                assert!(matches!(r.as_ref(), ConditionExpr::Comparison { .. }));
+            }
+            other => panic!("expected LogicalAnd, got {other:?}"),
+        }
